/**
 * IoT Pilot brand logo (neon night-halo mark) as an inline email attachment.
 * Embedded as base64 and attached via CID rather than <img src="http…"> so it
 * ships with the message (no external host) and renders wherever the client
 * shows images. Source: apps/frontend-ng/src/assets/logo-night-halo.png,
 * downscaled to 180px for email (~59 KB). Regenerate if the brand mark changes.
 *
 * NOTE: images can be gated behind "display images" in Gmail/Outlook; the
 * layout keeps alt="IoT Pilot" text so blocked-image recipients still see the name.
 */
export const BRAND_LOGO_CID = 'iotpilot-logo';
export const BRAND_LOGO_PNG_BASE64 =
  '';

/** Nodemailer attachment for the brand logo, referenced via cid:iotpilot-logo. */
export function brandLogoAttachment() {
  return {
    filename: 'iotpilot-logo.png',
    content: Buffer.from(BRAND_LOGO_PNG_BASE64, 'base64'),
    cid: BRAND_LOGO_CID,
    contentType: 'image/png',
  };
}
